"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { cn } from "@/lib/utils";
import {
    LayoutDashboard,
    Users,
    Wallet,
    PiggyBank,
    FileText,
    Settings,
    Menu,
    ChevronLeft,
    ChevronRight,
    LogOut,
    Zap
} from "lucide-react";
import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

const navigation = [
    { name: "Panel Spectre", href: "/", icon: LayoutDashboard },
    { name: "Censo", href: "/members", icon: Users },
    { name: "Ingresos", href: "/income", icon: Wallet },
    { name: "Gastos", href: "/expenses", icon: PiggyBank },
    { name: "Reportes", href: "/reports", icon: FileText },
    { name: "Ajustes", href: "/settings", icon: Settings },
];

export function Sidebar() {
    const pathname = usePathname();
    const [isOpen, setIsOpen] = useState(false);
    const [isCollapsed, setIsCollapsed] = useState(false);

    return (
        <>
            {/* Mobile Trigger */}
            <button
                className="fixed top-4 left-4 z-50 p-3 bg-zinc-900/80 backdrop-blur-md md:hidden rounded-xl border border-white/10 text-white shadow-xl"
                onClick={() => setIsOpen(!isOpen)}
            >
                <Menu className="h-6 w-6" />
            </button>

            {/* Mobile Overlay */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 bg-black/80 z-40 md:hidden backdrop-blur-sm"
                        onClick={() => setIsOpen(false)}
                    />
                )}
            </AnimatePresence>

            <motion.div
                className={cn(
                    "fixed inset-y-4 left-4 z-50 glass-panel rounded-3xl transform md:translate-x-0 transition-all duration-500 ease-out flex flex-col overflow-hidden",
                    isOpen ? "translate-x-0" : "-translate-x-[120%]",
                    isCollapsed ? "w-24" : "w-72"
                )}
            >
                {/* Header */}
                <div className="flex h-24 items-center px-6 relative">
                    {!isCollapsed ? (
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            className="flex items-center gap-3"
                        >
                            <div className="h-10 w-10 rounded-xl bg-gradient-to-br from-primary to-orange-600 flex items-center justify-center shadow-lg shadow-orange-500/20">
                                <Zap className="h-6 w-6 text-black fill-current" />
                            </div>
                            <div>
                                <h1 className="text-xl font-bold text-white tracking-wide">GESTIÓN</h1>
                                <p className="text-xs text-primary font-bold tracking-[0.2em]">FALLERA</p>
                            </div>
                        </motion.div>
                    ) : (
                        <div className="w-full flex justify-center">
                            <div className="h-10 w-10 rounded-xl bg-gradient-to-br from-primary to-orange-600 flex items-center justify-center shadow-lg shadow-orange-500/20">
                                <Zap className="h-6 w-6 text-black fill-current" />
                            </div>
                        </div>
                    )}

                    <button
                        onClick={() => setIsCollapsed(!isCollapsed)}
                        className="absolute -right-3 top-10 bg-zinc-800 border border-zinc-700 rounded-full p-1.5 text-zinc-400 hover:text-white shadow-lg hidden md:flex transition-transform hover:scale-110"
                    >
                        {isCollapsed ? <ChevronRight className="h-3 w-3" /> : <ChevronLeft className="h-3 w-3" />}
                    </button>
                </div>

                {/* Navigation */}
                <nav className="flex-1 space-y-2 px-4 py-6">
                    {navigation.map((item) => {
                        const isActive = pathname === item.href;
                        return (
                            <Link
                                key={item.name}
                                href={item.href}
                                className={cn(
                                    "group flex items-center px-4 py-3.5 text-sm font-medium rounded-2xl transition-all relative overflow-hidden",
                                    isActive
                                        ? "text-primary"
                                        : "text-zinc-400 hover:text-white hover:bg-white/5",
                                    isCollapsed ? "justify-center px-0" : ""
                                )}
                            >
                                {isActive && (
                                    <motion.div
                                        layoutId="active-nav-glow"
                                        className="absolute inset-0 bg-primary/10 rounded-2xl border border-primary/20 shadow-[0_0_20px_rgba(251,191,36,0.1)]"
                                        initial={false}
                                        transition={{ type: "spring", stiffness: 300, damping: 30 }}
                                    />
                                )}

                                <item.icon
                                    className={cn(
                                        "h-5 w-5 flex-shrink-0 transition-all duration-300 relative z-10",
                                        isActive ? "scale-110 drop-shadow-[0_0_8px_rgba(251,191,36,0.5)] fa-beat" : "group-hover:scale-110",
                                        isCollapsed ? "mr-0" : "mr-4"
                                    )}
                                />

                                {!isCollapsed && (
                                    <span className="relative z-10 tracking-wide">{item.name}</span>
                                )}

                                {isActive && !isCollapsed && (
                                    <motion.div
                                        layoutId="active-indicator"
                                        className="absolute right-4 w-1.5 h-1.5 rounded-full bg-primary shadow-[0_0_10px_#fbbf24]"
                                    />
                                )}
                            </Link>
                        );
                    })}
                </nav>

                {/* Footer Profile */}
                <div className="p-4 mt-auto">
                    <div className={cn(
                        "flex items-center p-3 rounded-2xl bg-zinc-900/50 border border-white/5 backdrop-blur-md transition-all hover:bg-zinc-800/50 cursor-pointer group",
                        isCollapsed ? "justify-center p-2" : ""
                    )}>
                        <div className="h-10 w-10 rounded-full bg-gradient-to-tr from-zinc-700 to-zinc-600 border-2 border-zinc-800 group-hover:border-primary/50 transition-colors flex items-center justify-center shrink-0">
                            <span className="font-bold text-xs text-white">TF</span>
                        </div>

                        {!isCollapsed && (
                            <div className="ml-3 overflow-hidden">
                                <p className="text-sm font-bold text-white truncate group-hover:text-primary transition-colors">Tesorería</p>
                                <p className="text-xs text-zinc-500 truncate">El Campanar</p>
                            </div>
                        )}

                        {!isCollapsed && (
                            <button className="ml-auto text-zinc-500 hover:text-red-400 transition-colors">
                                <LogOut className="h-4 w-4" />
                            </button>
                        )}
                    </div>
                </div>
            </motion.div>
        </>
    );
}
